sys_script_include.script:
var ChromaTechQueryLimitAjax = Class.create();
ChromaTechQueryLimitAjax.prototype = Object.extendsObject(global.AbstractAjaxProcessor, {

    getRequesterQueryCount: function() {
        var requesterId = this.getParameter('sysparm_requester_id');
        var requesterField = this.getParameter('sysparm_requester_field') || 'requester';
        var excludeSysId = this.getParameter('sysparm_exclude_sys_id'); // optional

        if (!requesterId)
            return "0";

        var ga = new GlideAggregate('x_1839224_chroma_0_chromatech_customer_queries');
        ga.addQuery(requesterField, requesterId);

        // Exclude current record when updating / editing
        if (excludeSysId && excludeSysId !== '-1')
            ga.addQuery('sys_id', '!=', excludeSysId);

        ga.addAggregate('COUNT');
        ga.query();

        if (ga.next())
            return ga.getAggregate('COUNT');

        return "0";
    },

    type: 'ChromaTechQueryLimitAjax'
});
